noncompliant:
using System;

namespace MyLibrary
{
    public class MyClass
    {
        string myUri;

        public string MyUri // Noncompliant - should be Uri type
        {
            get { return myUri; }
            set { myUri = value; }
        }

        public string ServiceUrl { get; set; } // Noncompliant
    }
}

compliant:
using System;

namespace MyLibrary
{
    public class MyClass
    {
        Uri myUri;

        public Uri MyUri // Compliant - uses System.Uri
        {
            get { return myUri; }
            set { myUri = value; }
        }

        public Uri ServiceUrl { get; set; } // Compliant
    }
}
